import React, { useState } from 'react';
import './CharactersCatalog.css';

const CharactersCatalog = () => {
  const [characters] = useState([
    {
      id: 1,
      name: 'Гатс',
      series: 'Berserk',
      image: 'https://placehold.co/300x400/ff6b6b/white?text=Гатс',
      description: 'Черный мечник, проклятый своей судьбой',
      popularity: 9.8,
      votes: 12450
    },
    {
      id: 2,
      name: 'Сун Джин-Ву',
      series: 'Solo Leveling',
      image: 'https://placehold.co/300x400/4ecdc4/white?text=Сун+Джин-Ву',
      description: 'Самый слабый охотник, ставший самым сильным',
      popularity: 9.7,
      votes: 8920
    },
    {
      id: 3,
      name: 'Наруто Узумаки',
      series: 'Naruto',
      image: 'https://placehold.co/300x400/45b7d1/white?text=Наруто',
      description: 'Хокаге седьмой, мечтающий стать хокаге',
      popularity: 9.5,
      votes: 15680
    },
    {
      id: 4,
      name: 'Эрен Йегер',
      series: 'Attack on Titan',
      image: 'https://placehold.co/300x400/96ceb4/white?text=Эрен',
      description: 'Обладатель силы титанов',
      popularity: 9.4,
      votes: 11230
    },
    {
      id: 5,
      name: 'Гриффит',
      series: 'Berserk',
      image: 'https://placehold.co/300x400/ffa726/white?text=Гриффит',
      description: 'Лидер Банды Ястреба',
      popularity: 9.2,
      votes: 8450
    },
    {
      id: 6,
      name: 'Лиорон',
      series: 'Tower of God',
      image: 'https://placehold.co/300x400/a55eea/white?text=Лиорон',
      description: 'Регуляр, поднимающийся по башне',
      popularity: 9.1,
      votes: 7230
    }
  ]);

  const [sortBy, setSortBy] = useState('popularity');
  const [searchTerm, setSearchTerm] = useState('');

  const filteredCharacters = characters.filter(character =>
    character.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    character.series.toLowerCase().includes(searchTerm.toLowerCase())
  ).sort((a, b) => {
    switch (sortBy) {
      case 'popularity':
        return b.popularity - a.popularity;
      case 'votes':
        return b.votes - a.votes;
      case 'name':
        return a.name.localeCompare(b.name);
      default:
        return b.popularity - a.popularity;
    }
  });

  return (
    <div className="characters-catalog">
      <div className="catalog-header">
        <h2>Персонажи</h2>
        
        <div className="catalog-controls">
          <div className="search-box">
            <i className="fas fa-search"></i>
            <input
              type="text"
              placeholder="Поиск персонажей..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          
          <div className="sort-controls">
            <select 
              value={sortBy} 
              onChange={(e) => setSortBy(e.target.value)}
              className="sort-select"
            >
              <option value="popularity">По популярности</option>
              <option value="votes">По голосам</option>
              <option value="name">По имени</option>
            </select>
          </div>
        </div>
      </div>
      
      <div className="characters-grid">
        {filteredCharacters.map(character => (
          <div key={character.id} className="character-card">
            <div className="character-image">
              <img src={character.image} alt={character.name} />
              <div className="character-popularity">
                <i className="fas fa-star"></i>
                {character.popularity}
              </div>
            </div>
            
            <div className="character-content">
              <h3 className="character-name">{character.name}</h3>
              <p className="character-series">{character.series}</p>
              <p className="character-description">{character.description}</p>
              
              <div className="character-stats">
                <div className="stat">
                  <span className="stat-label">Голосов</span>
                  <span className="stat-value">{character.votes.toLocaleString()}</span>
                </div>
                <button className="details-btn">
                  <i className="fas fa-info-circle"></i>
                  Подробнее
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default CharactersCatalog;
